module.exports = "          });\n        });\n        document.querySelectorAll(\"[data-team-wizard-prev]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            state.ui.teamOrchestrationStep = Math.max(1, (Number(state.ui.teamOrchestrationStep) || 1) - 1);\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-team-wizard-next]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            state.ui.teamOrchestrationStep = Math.min(3, (Number(state.ui.teamOrchestrationStep) || 1) + 1);\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-team-orchestration-generate]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const draft = state.ui.teamOrchestrationDraft;\n            if (draft && draft.dagRun) {\n              const ok = confirm(\"This will replace your current draft. Continue?\");\n              if (!ok) return;\n            }\n            const payload = readTeamOrchestrationDraftFromDom();\n            node.classList.add(\"chip-loading\");\n            node.textContent = \"Generating...\";\n            node.disabled = true;\n            vscode.postMessage({ type: \"generateTeamOrchestrationDraft\", payload });\n          });\n        });\n        document.querySelectorAll(\"[data-team-orchestration-save]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const draft = Object.assign({}, state.ui.teamOrchestrationDraft || {}, readTeamOrchestrationDraftFromDom());\n            node.classList.add(\"chip-loading\");\n            node.textContent = \"Saving...\";\n            node.disabled = true;\n            vscode.postMessage({ type: \"saveTeamOrchestrationDraft\", payload: { draft } });\n          });\n        });\n        document.querySelectorAll(\"[data-team-orchestration-add-worker]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const draft = readTeamOrchestrationDraftFromDom();\n            draft.workers.push({\n              title: \"Additional worker\",\n              role_id: \"implementer\",\n              role: \"Complete one bounded implementation slice.\",\n              model: draft.workerModel || \"gpt-5.3-codex\",\n              write_paths: [\"src\"],\n              expected_outputs: [\"implementation result\"],\n            });\n            state.ui.teamOrchestrationDraft = draft;\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-team-orchestration-remove-worker]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const removeIndex = Number.parseInt(node.dataset.teamOrchestrationRemoveWorker || \"-1\", 10);\n            const key = String(removeIndex);\n\n            if (state.pendingRemovals[key]) {\n              clearTimeout(state.pendingRemovals[key].timeoutId);\n              clearInterval(state.pendingRemovals[key].intervalId);\n              delete state.pendingRemovals[key];\n              const card = node.closest(\"[data-team-orchestration-worker]\");\n              if (card) card.classList.remove(\"removing\");\n              node.textContent = \"Remove\";\n              node.disabled = false;\n              return;\n            }\n\n            const card = node.closest(\"[data-team-orchestration-worker]\");\n            if (card) card.classList.add(\"removing\");\n            node.disabled = true;\n            let countdown = 3;\n            node.textContent = \"Undo (\" + countdown + \")\";\n\n            const intervalId = setInterval(() => {\n              countdown -= 1;\n              if (countdown > 0) {\n                node.textContent = \"Undo (\" + countdown + \")\";\n              }\n            }, 1000);\n\n            const timeoutId = setTimeout(() => {\n              clearInterval(intervalId);\n              delete state.pendingRemovals[key];\n              const draft = readTeamOrchestrationDraftFromDom();\n              draft.workers = draft.workers.filter((_, index) => index !== removeIndex);\n              draft.workerCount = draft.workers.length;\n              state.ui.teamOrchestrationDraft = draft;\n              render(state.payload);\n            }, 3000);\n\n            state.pendingRemovals[key] = { timeoutId, intervalId };\n          });\n        });\n        document.querySelectorAll('[data-team-orchestration-worker-field=\"role_id\"]').forEach((node) => {\n          node.addEventListener(\"change\", () => {\n            const roleId = normalizeRoleTemplateId(node.value);\n            const iconUrl = getRoleTemplateIconUrl(roleId, rolePluginTemplatesFromState());\n            const card = node.closest(\"[data-team-orchestration-worker]\");\n            const iconEl = card && card.querySelector(\".team-role-icon\");\n            if (iconEl) {\n              if (iconUrl) {\n                iconEl.src = iconUrl;\n                iconEl.style.display = \"\";\n              } else {\n                iconEl.style.display = \"none\";\n              }\n            }\n          });\n        });\n        document.querySelectorAll(\"[data-team-definition-save]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const taskId = node.dataset.teamDefinitionSave || \"\";\n            const fields = Array.from(document.querySelectorAll(\"[data-team-definition-field]\"))\n              .filter((fieldNode) => fieldNode.dataset.teamTaskId === taskId);\n            const valueFor = (name) => {\n              const fieldNode = fields.find((item) => item.dataset.teamDefinitionField === name);\n              return fieldNode && \"value\" in fieldNode ? fieldNode.value : \"\";\n            };\n            const feedbackNode = document.querySelector('[data-team-definition-feedback=\"' + taskId + '\"]');\n            node.textContent = \"Saving...\";\n            node.disabled = true;\n            if (feedbackNode) feedbackNode.textContent = \"Saving\";\n            vscode.postMessage({\n              type: \"updateTeamTaskDefinition\",\n              payload: {\n                taskId,\n                title: valueFor(\"title\"),\n                prompt: valueFor(\"prompt\"),\n                acceptanceCriteria: valueFor(\"criteria\"),\n              },\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-team-definition-cancel]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const taskId = node.dataset.teamDefinitionCancel || \"\";\n            const feedbackNode = document.querySelector('[data-team-definition-feedback=\"' + taskId + '\"]');\n            if (feedbackNode) feedbackNode.textContent = \"Canceled\";\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-team-delete-workspace]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            node.textContent = \"Archiving...\";\n            node.disabled = true;\n            vscode.postMessage({ type: \"deleteTeamWorkspace\", workspaceId: node.dataset.teamDeleteWorkspace || \"\" });\n          });\n        });\n        document.querySelectorAll(\"[data-team-run-snake-demo]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const promptNode = document.querySelector(\"[data-team-snake-prompt]\");\n            const feedbackNode = document.querySelector(\"[data-team-run-feedback]\");\n            node.textContent = \"Run success\";\n            node.disabled = true;\n            if (feedbackNode) feedbackNode.textContent = \"Run request sent\";\n            vscode.postMessage({\n              type: \"runTeamSnakeDemo\",\n              threadId: node.dataset.teamThread || state.selectedThreadId || \"\",\n              prompt: promptNode && \"value\" in promptNode ? promptNode.value : \"\",\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-copy-team-snake-prompt]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const promptNode = document.querySelector(\"[data-team-snake-prompt]\");\n            vscode.postMessage({\n              type: \"copyText\",\n              text: promptNode && \"value\" in promptNode ? promptNode.value : \"\",\n              label: \"Team run prompt\",\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-clear-thread-tab-filter]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            setActiveBoardTab(\"all\");\n          });\n        });\n        document.querySelectorAll(\"[data-codex-thread]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            markCodexLinking(node.dataset.codexThread, \"sidebar\");\n            render(state.payload);\n            vscode.postMessage({\n              type: \"revealInCodexSidebar\",\n              threadId: node.dataset.codexThread,\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-open-codex-editor]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            markCodexLinking(node.dataset.openCodexEditor, \"editor\");\n            render(state.payload);\n            vscode.postMessage({\n              type: \"openInCodexEditor\",\n              threadId: node.dataset.openCodexEditor,\n            });\n          });\n        });\n        document.querySelectorAll(\"[data-set-handoff]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            upsertHandoffCue(node.dataset.setHandoff);\n          });\n        });\n        document.querySelectorAll(\"[data-clear-handoff]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            clearHandoffCue(node.dataset.clearHandoff);\n          });\n        });\n        document.querySelectorAll(\"[data-focus-thread]\").forEach((node) => {\n          node.addEventListener(\"click\", (event) => {\n            event.stopPropagation();\n            const threadId = node.dataset.focusThread;\n            if (!threadId) return;\n            setSelectedThread(threadId, { openDrawer: true });\n            vscode.postMessage({ type: \"selectThread\", threadId });\n          });\n        });\n        document.querySelectorAll(\"[data-group]\").forEach((node) => {\n          node.addEventListener(\"toggle\", () => {\n            state.ui.groups[node.dataset.group] = node.open;\n            persistUi();\n          });\n        });\n        document.querySelectorAll(\"[data-batch-select]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            clearPendingBatch();\n            filteredThreads.forEach((thread) => {\n              state.ui.selected[thread.id] = true;\n            });\n            persistUi();\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-batch-clear]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            clearSelection();\n          });\n        });\n        document.querySelectorAll(\"[data-batch-action]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const action = node.dataset.batchAction;\n            const threadIds = filteredThreads.filter((thread) => isSelected(thread.id)).map((thread) => thread.id);\n            if (!threadIds.length) return;\n            if (action === \"copy_ids\") {\n              vscode.postMessage({\n                type: \"copyText\",\n                text: threadIds.join(\"\\n\"),\n                label: \"Thread IDs\",\n              });\n              return;\n            }\n            if (action === \"attach_board\") {\n              attachThreadsToBoard(threadIds);\n              return;\n            }\n            if (action === \"set_tab\") {\n              vscode.postMessage({\n                type: \"batchSetBoardTab\",\n                threadIds,\n                activeBoardTab: state.ui.activeBoardTab || \"all\",\n                boardTabOrder: state.ui.boardTabOrder || [],\n              });\n              return;\n            }\n            const meta = getBatchActionMeta(action);\n            if (meta.requiresConfirm) {\n              if (action === \"hard_delete\" && !canDispatchHardDeleteRequest()) return;\n              setPendingBatch(action, threadIds);\n              render(state.payload);\n              return;\n            }\n            if (!canDispatchLifecycleRequest()) return;\n            vscode.postMessage({ type: \"lifecycleBatch\", action, threadIds });\n          });\n        });\n        document.querySelectorAll(\"[data-batch-cancel]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            clearPendingBatch();\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-batch-confirm]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            if (!state.ui.pendingBatch || !state.ui.pendingBatch.threadIds.length) return;\n            const { action, threadIds } = state.ui.pendingBatch;\n            clearPendingBatch();\n            render(state.payload);\n            if (action === \"hard_delete\" && !canDispatchHardDeleteRequest()) return;\n            if (!canDispatchLifecycleRequest()) return;\n            vscode.postMessage({ type: \"lifecycleBatch\", action, threadIds });\n          });\n        });\n\n        const runningThreads = effectiveRunningThreads;\n        document.querySelectorAll(\"[data-subtab]\").forEach((node) => {\n          node.classList.toggle(\"active\", node.dataset.subtab === state.ui.rightPaneTab);\n        });\n        document.querySelectorAll(\"[data-pane]\").forEach((node) => {\n          node.classList.toggle(\"active\", node.dataset.pane === state.ui.rightPaneTab);\n        });\n        setNodeHtml(\"runningTabs\", [\n          '<button class=\"tab ' + (state.selectedThreadId ? '' : 'active') + '\" data-running-thread=\"\">Overview</button>',\n          ...runningThreads.map((thread) => '<button class=\"tab ' + (state.selectedThreadId === thread.id ? 'active' : '') + '\" data-running-thread=\"' + esc(thread.id) + '\">' + esc(short(displayThreadTitle(thread, thread.id), 28)) + '</button>')\n        ].join(\"\"));\n\n        document.querySelectorAll(\"[data-running-thread]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            const threadId = node.dataset.runningThread || undefined;\n            vscode.postMessage({ type: \"selectThread\", threadId });\n          });\n        });\n\n        const selected = (dashboard.threads || []).find((thread) => thread.id === state.selectedThreadId) || filteredThreads[0] || runningThreads[0] || dashboard.threads[0];\n        const terminalLogs = selected ? (selected.preview_logs || []) : [];\n        setNodeHtml(\"terminal\", terminalLogs.map((log) => {\n          return '<div class=\"terminal-line\"><span class=\"muted\">' + esc(log.ts_iso || \"\") + '</span> ' +\n            '<strong>' + esc(log.level || \"INFO\") + '</strong> ' +\n            esc(log.message || log.target || \"log event\") + '</div>';\n        }).join(\"\") || '<div class=\"empty-state\">No recent log preview available.</div>');\n\n        const detailThread = (payload.detail && payload.detail.thread) || {};\n        const history = (detailThread.id && detailThread.id === (selected && selected.id) ? (detailThread.history || []) : []) || (selected ? (selected.history || []) : []);\n        setNodeText(\"historySummary\",\n          history.length\n            ? (\"Showing \" + history.length + \" messages for \" + short((selected && selected.title) || detailThread.title || \"selected thread\", 48))\n            : \"Select a thread to inspect its chat history.\");\n        setNodeHtml(\"chatWindow\", history.map((item) => {\n          return '<div class=\"chat ' + esc(item.role || \"assistant\") + '\">' +\n            '<div class=\"chat-head\"><span>' + esc(item.role || \"assistant\") + '</span><span>' + esc(item.ts || \"\") + '</span></div>' +\n            '<div>' + esc(item.text || \"\") + '</div>' +\n          '</div>';\n        }).join(\"\") || '<div class=\"empty-state\">Select a thread to inspect its chat history.</div>');\n        document.querySelectorAll(\"[data-open-drawer]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            state.ui.drawerOpen = true;\n            persistUi();\n            render(state.payload);\n          });\n        });\n        document.querySelectorAll(\"[data-subtab-shortcut]\").forEach((node) => {\n          node.addEventListener(\"click\", () => {\n            state.ui.rightPaneTab = node.dataset.subtabShortcut;\n            state.ui.drawerOpen = true;\n            persistUi();\n            render(state.payload);\n          });\n        });\n\n        renderDetail(payload);\n        applyPanelLanguageChrome();\n      }\n";
